import{_ as t,o,c as a,a3 as r}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"90. Make Up Time","description":"","frontmatter":{"title":"90. Make Up Time","eba":"Mental Health Services 2024-2028","topics":["hours","shift-work"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/hours-of-work/90-make-up-time.md","filePath":"ebas/mental-health/rpn-pen-mho/hours-of-work/90-make-up-time.md"}'),n={name:"ebas/mental-health/rpn-pen-mho/hours-of-work/90-make-up-time.md"};function i(s,e,p,m,h,l){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="_90-make-up-time" tabindex="-1">90. Make Up Time <a class="header-anchor" href="#_90-make-up-time" aria-label="Permalink to &quot;90. Make Up Time&quot;">​</a></h1><p><strong>90.1</strong> Notwithstanding provisions elsewhere in the agreement, the Employer and the majority of Employees at an enterprise may agree to establish a system of make- up time provided that:</p><p><strong>(a)</strong> An Employee may elect, with the consent of the Employer, to work make-up time under which the Employee takes time off during ordinary hours, and works those hours at a later time, during the spread of ordinary hours provided in the agreement.</p><p><strong>(b)</strong> An Employee on shift work may elect, with the consent of the Employer, to work make-up time under which the Employee takes time-off ordinary hours and works those hours at a later time, at the shift work rate which would have been applicable to the hours taken off.</p><p><strong>90.2</strong> Clause 90.1 is subject to the Employer also informing each union of its intention to introduce an enterprise system of make-up time flexibility, and providing a reasonable opportunity for the union(s) to participate in negotiations.</p><p><strong>90.3</strong> Once a decision has been taken to introduce an enterprise system of make-up time, in accordance with this clause, its terms must be set out in the time and wages records kept pursuant to Fair Work Regulations 2009 (Cth).</p>',6)])])}const c=t(n,[["render",i]]);export{d as __pageData,c as default};
